#include<bits/stdc++.h>
using namespace std;
const long long mod=1004535809;
long long fastpow(long long x,long long y)
{
    long long sum=1;
    while(y)
    {
        if(y%2==1)
        {
            sum=sum*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return sum;
}
long long dp[1000010];
long long jc[1000010],ny[1000010];
int C(int n,int m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
int main()
{
    jc[0]=ny[0]=1;
    for(int i=1;i<=1000000;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[1000000]=fastpow(jc[1000000],mod-2);
    for(int i=999999;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    dp[1]=1;
    for(int i=1;i<=1000;i++)
    {
        dp[i]=fastpow(2,i*(i-1)/2);
        for(int j=1;j<i;j++)
        {
            dp[i]-=C(i-1,j-1)*dp[j]%mod*fastpow(2,(i-j)*(i-j-1)/2)%mod;
            dp[i]=(dp[i]%mod+mod)%mod;
        }
    }
    int n;
    scanf("%d",&n);
    printf("%lld",dp[n]);
    return 0;
}
